# Structure Chart Representation: Calculator System
# Level 0: Main Module
# Level 1: Get Input, Perform Operation, Display Result
# Level 2: Add, Subtract, Multiply, Divide (children of Perform Operation)

def get_numbers():
    """Level 1 Module: Get two numbers from user"""
    try:
        num1 = float(input("Enter first number: "))
        num2 = float(input("Enter second number: "))
        return num1, num2
    except ValueError:
        print("Invalid input! Please enter numeric values.")
        return None, None

def add(a, b):
    """Level 2 Module: Addition"""
    return a + b

def subtract(a, b):
    """Level 2 Module: Subtraction"""
    return a - b

def multiply(a, b):
    """Level 2 Module: Multiplication"""
    return a * b

def divide(a, b):
    """Level 2 Module: Division with zero check"""
    if b == 0:
        return None
    return a / b

def perform_operation(num1, num2, choice):
    """Level 1 Module: Controls which operation to perform"""
    operations = {
        '1': ('Add', add),
        '2': ('Subtract', subtract),
        '3': ('Multiply', multiply),
        '4': ('Divide', divide)
    }

    if choice in operations:
        name, func = operations[choice]
        result = func(num1, num2)
        return name, result
    return None, None

def display_result(operation_name, result):
    """Level 1 Module: Display the result"""
    if result is None:
        print("Error: Cannot perform operation.")
    else:
        print(f"Result of {operation_name}: {result}")

def main():
    """Level 0 Module: Main controller (root of structure chart)"""
    print("=== Simple Calculator ===")
    print("1. Add\n2. Subtract\n3. Multiply\n4. Divide")

    choice = input("Enter operation (1-4): ")
    num1, num2 = get_numbers()

    if num1 is not None and num2 is not None:
        operation_name, result = perform_operation(num1, num2, choice)
        display_result(operation_name, result)

if __name__ == "__main__":
    main()

# Structure Chart with Data Coupling: Student Record Management
# Demonstrates passing data between modules (student records)

class Student:
    """Data structure for student record"""
    def __init__(self, student_id, name, marks):
        self.student_id = student_id
        self.name = name
        self.marks = marks

    def __repr__(self):
        return f"ID: {self.student_id}, Name: {self.name}, Marks: {self.marks}"

# Level 1 Module: Input Module
def collect_student_data():
    """Level 1: Collects student data from user - returns Student object"""
    student_id = input("Enter Student ID: ")
    name = input("Enter Student Name: ")
    try:
        marks = float(input("Enter Marks: "))
    except ValueError:
        marks = 0.0

    student = Student(student_id, name, marks)
    return student  # Data coupling: Student object passed to caller

# Level 2 Modules: Validation (subordinate to collect_student_data)
def validate_marks(marks):
    """Validates marks are in valid range"""
    return 0 <= marks <= 100

def validate_student_id(student_id):
    """Validates student ID format"""
    return len(student_id) > 0 and student_id.isalnum()

# Level 1 Module: Processing Module
def calculate_grade(student):
    """Level 1: Calculates grade based on marks - accepts and returns Student"""
    marks = student.marks

    if marks >= 90:
        grade = 'A'
    elif marks >= 80:
        grade = 'B'
    elif marks >= 70:
        grade = 'C'
    elif marks >= 60:
        grade = 'D'
    else:
        grade = 'F'

    # Return updated student with grade
    return Student(student.student_id, student.name, marks)

# Level 2 Module: Analysis (subordinate to calculate_grade)
def check_distinction(marks):
    """Checks if student qualifies for distinction"""
    return marks >= 90

# Level 1 Module: Storage Module
def save_student_record(student, database):
    """Level 1: Saves student to database - data coupling shown here"""
    database.append(student)
    return True

def load_student_records(database):
    """Level 1: Loads all records from database"""
    return database

# Level 1 Module: Display Module
def format_student_record(student):
    """Level 1: Formats student data for display"""
    return f"{student.student_id} | {student.name} | {student.marks}"

def display_students(students):
    """Level 1: Displays all student records"""
    print("\n--- Student Records ---")
    for student in students:
        print(format_student_record(student))

# Level 0 Module: Main Controller
def student_management_system():
    """Level 0: Main module - controls all subordinate modules"""
    database = []  # Shared data store

    while True:
        print("\n=== Student Management ===")
        print("1. Add Student")
        print("2. Display All Students")
        print("3. Exit")
        choice = input("Enter choice: ")

        if choice == '1':
            # Data flows: collect_student_data -> calculate_grade -> save_student_record
            student = collect_student_data()
            student = calculate_grade(student)
            save_student_record(student, database)
            print("Student added successfully!")

        elif choice == '2':
            students = load_student_records(database)
            display_students(students)

        elif choice == '3':
            print("Exiting system...")
            break

        else:
            print("Invalid choice!")

if __name__ == "__main__":
    student_management_system()
